import 'server-only'
import { prisma } from '@/lib/prisma'
import type { InspectionSearchInput } from './schema'

export async function getInspections(params: InspectionSearchInput) {
    const where = {
        ...(params.targetType && { targetType: params.targetType }),
        ...(params.status && { status: params.status }),
    }

    const [items, total] = await prisma.$transaction([
        prisma.inspection.findMany({
            where,
            select: {
                id: true,
                targetType: true,
                targetId: true,
                status: true,
                comment: true,
                inspectorId: true,
                createdAt: true,
                updatedAt: true,
            },
            skip: params.page * params.size,
            take: params.size,
            orderBy: { createdAt: 'desc' },
        }),
        prisma.inspection.count({ where }),
    ])

    return { items, total }
}

'use server'
import { prisma } from '@/lib/prisma'
import { requireAdmin } from '@/lib/auth'
import { revalidatePath } from 'next/cache'
import { inspectionUpdateSchema } from './schema'
import type { ActionResult } from '@/lib/errors'

export async function updateInspection(
    id: number,
    input: unknown
): Promise<ActionResult> {
    try {
        await requireAdmin()
        const parsed = inspectionUpdateSchema.safeParse(input)
        if (!parsed.success) {
            return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
        }
        await prisma.inspection.update({
            where: { id },
            data: { status: parsed.data.status, comment: parsed.data.comment ?? null },
        })
        revalidatePath('/inspection')
        return { success: true, data: undefined }
    } catch (e) {
        console.error('updateInspection error:', e)
        return { success: false, error: '검수 상태 변경 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' }
    }
}

