    PENDING: 'outline',
    APPROVED: 'default',
    REJECTED: 'destructive',
}

const columnDefs: ColDef<InspectionItem>[] = [
    { field: 'id', headerName: '번호', width: 80 },
    {
        field: 'targetType',
        headerName: '대상 유형',
        width: 100,
        valueFormatter: (params: ValueFormatterParams<InspectionItem, string>) =>
            TARGET_TYPE_LABEL[params.value ?? ''] ?? params.value ?? '',
    },
    { field: 'targetId', headerName: '대상 ID', width: 100 },
    {
        field: 'status',
        headerName: '상태',
        width: 100,
        cellRenderer: (params: { value: string }) => {
            const label = STATUS_LABEL[params.value] ?? params.value
            const variant = STATUS_VARIANT[params.value] ?? 'outline'
            return `<span data-status="${params.value}" data-variant="${variant}">${label}</span>`
        },
        valueFormatter: (params: ValueFormatterParams<InspectionItem, string>) =>
            STATUS_LABEL[params.value ?? ''] ?? params.value ?? '',
    },
    {
        field: 'comment',
        headerName: '검수 의견',
        flex: 1,
        valueFormatter: (params: ValueFormatterParams<InspectionItem, string | null>) =>
            params.value ?? '-',
    },
    {
        field: 'createdAt',
        headerName: '등록일',
        width: 120,
        valueFormatter: (params: ValueFormatterParams<InspectionItem, Date>) =>
            params.value ? format(new Date(params.value), 'yyyy-MM-dd') : '',
    },
]

export function InspectionTable({ items, onRowClick }: InspectionTableProps) {
    return (
        <DataTable<InspectionItem>
            columnDefs={columnDefs}
            rowData={items}
            onRowClick={onRowClick}
        />
