'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { format } from 'date-fns'
import { toast } from 'sonner'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Textarea } from '@/components/ui/textarea'
import { updateInspection } from '@/features/inspection/actions'
import type { InspectionItem } from '@/features/inspection/types'

interface InspectionDetailPanelProps {
    inspection: InspectionItem | null
    open: boolean
    onOpenChange: (open: boolean) => void
}

const TARGET_TYPE_LABEL: Record<string, string> = {
    WORD: '단어',
    TERM: '용어',
}

const STATUS_LABEL: Record<string, string> = {
    PENDING: '대기',
    APPROVED: '승인',
    REJECTED: '반려',
}

export function InspectionDetailPanel({ inspection, open, onOpenChange }: InspectionDetailPanelProps) {
    const router = useRouter()
    const [rejectComment, setRejectComment] = useState('')
    const [rejectMode, setRejectMode] = useState(false)
    const [loading, setLoading] = useState(false)

    const handleApprove = async () => {
        if (!inspection) return
        setLoading(true)
        try {
            const result = await updateInspection(inspection.id, { status: 'APPROVED' })
            if (!result.success) {
                toast.error(result.error ?? '승인 중 오류가 발생했습니다')
                return
            }
            toast.success('승인되었습니다')
            onOpenChange(false)
            router.refresh()
        } catch (e) {
            console.error('handleApprove error:', e)
            toast.error('승인 중 오류가 발생했습니다')
        } finally {
            setLoading(false)
        }
    }

    const handleReject = async () => {
        if (!inspection) return
        setLoading(true)
        try {
            const result = await updateInspection(inspection.id, {
                status: 'REJECTED',
                comment: rejectComment || undefined,
            })
            if (!result.success) {
                toast.error(result.error ?? '반려 중 오류가 발생했습니다')
                return
            }
            toast.success('반려되었습니다')
            setRejectComment('')
            setRejectMode(false)
            onOpenChange(false)
            router.refresh()
        } catch (e) {
            console.error('handleReject error:', e)
            toast.error('반려 중 오류가 발생했습니다')
        } finally {
            setLoading(false)
        }
    }

    const handleOpenChange = (open: boolean) => {
        if (!open) {
            setRejectMode(false)
            setRejectComment('')
        }
        onOpenChange(open)
    }

    if (!inspection) return null

    return (
        <Dialog open={open} onOpenChange={handleOpenChange}>
            <DialogContent className="sm:max-w-[480px]">
                <DialogHeader>
                    <DialogTitle>검수 상세</DialogTitle>
                </DialogHeader>
                <dl className="grid grid-cols-[120px_1fr] gap-x-4 gap-y-3 text-sm">
                    <dt className="font-medium text-slate-500">ID</dt>
                    <dd>{inspection.id}</dd>
                    <dt className="font-medium text-slate-500">대상 유형</dt>
                    <dd>{TARGET_TYPE_LABEL[inspection.targetType] ?? inspection.targetType}</dd>
                    <dt className="font-medium text-slate-500">대상 ID</dt>
                    <dd>{inspection.targetId}</dd>
                    <dt className="font-medium text-slate-500">상태</dt>
                    <dd>{STATUS_LABEL[inspection.status] ?? inspection.status}</dd>
                    <dt className="font-medium text-slate-500">검수 의견</dt>
                    <dd>{inspection.comment ?? '-'}</dd>
                    <dt className="font-medium text-slate-500">등록일</dt>
                    <dd>{format(new Date(inspection.createdAt), 'yyyy-MM-dd')}</dd>
                </dl>

                {inspection.status === 'PENDING' && (
                    <div className="pt-4 space-y-3">
                        {rejectMode ? (
                            <>
                                <Textarea
                                    placeholder="반려 의견을 입력하세요"
                                    value={rejectComment}
                                    onChange={(e) => setRejectComment(e.target.value)}
                                    rows={3}
                                />
                                <div className="flex justify-end gap-2">
                                    <Button
                                        variant="outline"
                                        onClick={() => {
                                            setRejectMode(false)
                                            setRejectComment('')
                                        }}
                                        disabled={loading}
                                    >
                                        취소
                                    </Button>
                                    <Button
                                        variant="destructive"
                                        onClick={handleReject}
                                        disabled={loading}
                                    >
                                        {loading ? '처리 중...' : '반려 확인'}
                                    </Button>
                                </div>
                            </>
                        ) : (
                            <div className="flex justify-end gap-2">
                                <Button
                                    variant="destructive"
                                    onClick={() => setRejectMode(true)}
                                    disabled={loading}
                                >
                                    반려
                                </Button>
                                <Button
                                    onClick={handleApprove}
                                    disabled={loading}
                                >
                                    {loading ? '처리 중...' : '승인'}
                                </Button>
                            </div>
                        )}
                    </div>
                )}
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState } from 'react'
