                                        disabled={loading}
                                    >
                                        취소
                                    </Button>
                                    <Button
                                        variant="destructive"
                                        onClick={handleReject}
                                        disabled={loading}
                                    >
                                        {loading ? '처리 중...' : '반려 확인'}
                                    </Button>
                                </div>
                            </>
                        ) : (
                            <div className="flex justify-end gap-2">
                                <Button
                                    variant="destructive"
                                    onClick={() => setRejectMode(true)}
                                    disabled={loading}
                                >
                                    반려
                                </Button>
                                <Button
                                    onClick={handleApprove}
                                    disabled={loading}
                                >
                                    {loading ? '처리 중...' : '승인'}
                                </Button>
                            </div>
                        )}
                    </div>
                )}
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState } from 'react'
import { InspectionTable } from './InspectionTable'
import { InspectionDetailPanel } from './InspectionDetailPanel'
import type { InspectionItem } from '../types'

interface InspectionViewProps {
    items: InspectionItem[]
}

export function InspectionView({ items }: InspectionViewProps) {
    const [selected, setSelected] = useState<InspectionItem | null>(null)
    const [detailOpen, setDetailOpen] = useState(false)

    const handleRowClick = (item: InspectionItem) => {
        setSelected(item)
        setDetailOpen(true)
    }

    return (
        <>
            <InspectionTable items={items} onRowClick={handleRowClick} />
            <InspectionDetailPanel
                inspection={selected}
                open={detailOpen}
                onOpenChange={setDetailOpen}
            />
        </>
    )
}

import { getInspections } from '@/features/inspection/queries'
